CREATE TABLE public.active_emergencies (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), broadcast_id uuid NOT NULL REFERENCES public.broadcasts(id), emergency_type text NOT NULL CHECK (emergency_type = ANY (ARRAY['active_threat', 'fire', 'earthquake', 'flooding'])), status text NOT NULL DEFAULT 'active' CHECK (status = ANY (ARRAY['active', 'resolved'])), resolved_at timestamptz, created_at timestamptz DEFAULT now(), school_id text DEFAULT 'sscrmnl'); ALTER TABLE public.active_emergencies ENABLE ROW LEVEL SECURITY; CREATE POLICY "Read emergencies" ON public.active_emergencies FOR SELECT USING (true); CREATE POLICY "Admins insert emergencies" ON public.active_emergencies FOR INSERT WITH CHECK (EXISTS (SELECT 1 FROM profiles WHERE profiles.id = (SELECT auth.uid()) AND profiles.role = ANY (ARRAY['admin', 'super_admin']))); CREATE POLICY "Admins update emergencies" ON public.active_emergencies FOR UPDATE USING (EXISTS (SELECT 1 FROM profiles WHERE profiles.id = (SELECT auth.uid()) AND profiles.role = ANY (ARRAY['admin', 'super_admin']))); ALTER PUBLICATION supabase_realtime ADD TABLE public.active_emergencies;;
